// Test that ByteAddressBuffer.Load<T>/Store<T> with interface type works correctly.
//TEST:COMPARE_COMPUTE(filecheck-buffer=CHECK):-cpu -output-using-type -conformance "ImplA:IFoo=1"
//TEST:SIMPLE(filecheck=CHECK):-target spirv -conformance "ImplA:IFoo=1"

[anyValueSize(8)]
interface IFoo
{
    float getValue();
}

struct ImplA : IFoo
{
    float v;
    float getValue() { return v; }
}

RWByteAddressBuffer byteBuffer : register(u0);
RWStructuredBuffer<float> outputBuffer : register(u1);

[numthreads(1, 1, 1)]
void computeMain()
{
    ImplA a;
    a.v = 7.0;
    IFoo fooA = a;
    byteBuffer.Store<IFoo>(0, fooA);

    IFoo loaded = byteBuffer.Load<IFoo>(0);
    outputBuffer[0] = loaded.getValue();
    //CHECK: 7.0
}

